const n = parseInt(process.argv[2]);
let sum = 0;
for (let i = 1; i <= n; i++) {
    sum = (sum + i) % 1000000007;
}
console.log(sum);

const n = parseInt(process.argv[2]);
let a = 0, b = 1;
for (let i = 0; i < n; i++) {
    const temp = b;
    b = (a + b) % 1000000007;
    a = temp;
}
console.log(a);

const limit = parseInt(process.argv[2]);
const sieve = new Uint8Array(limit + 1);
let count = 0;
for (let i = 2; i <= limit; i++) {
    if (!sieve[i]) {
        count++;
        for (let j = i * i; j <= limit; j += i)
            sieve[j] = 1;
    }
}
console.log(count);

const n = parseInt(process.argv[2]);
const arr = new Array(n);
let seed = 42;
for (let i = 0; i < n; i++) {
    seed = ((Math.imul(seed, 1103515245) + 12345) >>> 0) % 2147483648;
    arr[i] = (seed >> 16) % 1000;
}
const counts = new Array(1000).fill(0);
for (const v of arr) counts[v]++;
const sorted = [];
for (let v = 0; v < 1000; v++)
    for (let c = 0; c < counts[v]; c++)
        sorted.push(v);
let checksum = 0;
for (const v of sorted) checksum = (checksum + v) % 1000000007;
console.log(`${sorted[0]} ${sorted[n - 1]} ${checksum}`);

const n = parseInt(process.argv[2]);
const arr = new Array(n);
let seed = 42;
for (let i = 0; i < n; i++) { seed=((Math.imul(seed,1103515245)+12345)>>>0)%2147483648; arr[i]=((seed>>16)&0x7fff)%n; }
const seen = new Set();
let count = 0;
for (const x of arr) { if (n-x>=0 && seen.has(n-x)) count++; seen.add(x); }
console.log(count);
